<template><main class="dash"><section class="hero"><p class="kicker">Ops</p><h1>Delivery Health</h1><p>Status report, file deliverables, Discord delivery log, retry queue.</p><button @click="generate" :disabled="loading">{{loading?'Generating…':'Generate + Send Report'}}</button></section><section v-if="data" class="grid"><article class="panel"><h2>Latest</h2><b>{{data.latest_report}}</b><p><a :href="data.local" target="_blank">Local</a> · <a :href="data.tailscale" target="_blank">Tailscale</a></p></article><article class="panel"><h2>Deliverables</h2><p v-for="(v,k) in data.deliverables" :key="k"><b>{{k}}</b>: {{v?'OK':'MISSING'}}</p></article></section><section class="panel" v-if="data"><h2>Send Queue</h2><div class="summary"><span v-for="x in queueSummary" :key="x.status" :class="x.status">{{x.status}}: {{x.count}}</span><span v-if="!queueSummary.length" class="ok">empty</span></div><div class="log queue" v-for="x in queueRows" :key="x.id"><b>#{{x.id}} {{x.step}}</b><span :class="x.status">{{x.status}}</span><small>{{x.channel}} · {{x.slug}} · attempts {{x.attempts}} · next {{x.next_attempt_at||'-'}} · {{x.last_error||'no error'}}</small></div></section><section class="panel" v-if="data"><h2>Delivery Log</h2><div class="log" v-for="x in data.delivery" :key="x.step+x.created_at"><b>{{x.step}}</b><span :class="x.status">{{x.status}}</span><small>{{x.detail}} · {{x.created_at}}</small></div></section></main></template>
<script setup>import{ref,computed,onMounted}from'vue';import{apiGet,apiPost}from'../lib/api';const data=ref(null),loading=ref(false);const queueSummary=computed(()=>data.value?.send_queue?.summary||[]);const queueRows=computed(()=>data.value?.send_queue?.pending_failed||[]);async function load(){data.value=await apiGet('/api/report-health')}async function generate(){loading.value=true;try{await apiPost('/api/ai-daily-report/generate',{});await load()}finally{loading.value=false}}onMounted(load)</script>
<style scoped>.dash{max-width:1100px;margin:auto;padding:24px 14px 70px;color:var(--ink)}.hero,.panel{background:var(--bg2);border:2px solid var(--line-strong);box-shadow:5px 5px 0 var(--line-strong);padding:18px;margin-bottom:16px}.hero{background:#facc15}.hero h1{font-size:clamp(42px,8vw,80px);margin:0;letter-spacing:-.07em}.kicker{text-transform:uppercase;font-weight:900;color:#9a3412}.grid{display:grid;grid-template-columns:1fr 1fr;gap:16px}.log{display:grid;grid-template-columns:160px 90px 1fr;gap:10px;border-top:1px solid var(--line);padding:10px}.queue{grid-template-columns:190px 90px 1fr}.summary{display:flex;flex-wrap:wrap;gap:8px;margin:8px 0 12px}.summary span{border:2px solid var(--line-strong);padding:6px 10px;font-weight:900}.ok,.sent,.done{color:var(--green);font-weight:900}.fail,.failed{color:var(--red);font-weight:900}.pending{color:var(--accent2);font-weight:900}.running,.retry{color:var(--accent);font-weight:900}button{border:2px solid var(--line-strong);background:var(--ink);color:var(--accent2);padding:10px 14px;font-weight:900}@media(max-width:720px){.grid,.log,.queue{grid-template-columns:1fr}} </style>
